$ErrorActionPreference = "Stop"
Set-Location "C:\Users\mike.balducci\downloads\onsiteaffiliate.com"

Write-Host "`n=== Step 1: Install @supabase/supabase-js ===" -ForegroundColor Cyan
npm install @supabase/supabase-js

Write-Host "`n=== Step 2: Writing files (base64 decode) ===" -ForegroundColor Cyan

function Write-B64File {
    param([string]$Path, [string]$B64)
    $fullPath = Join-Path $PWD $Path
    $dir = Split-Path $fullPath -Parent
    if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    [System.IO.File]::WriteAllBytes($fullPath, [System.Convert]::FromBase64String($B64))
    Write-Host "  Created: $Path" -ForegroundColor Green
}

Write-B64File "src\supabaseClient.js" ""
Write-B64File "src\defaultSlides.js" ""
Write-B64File "src\usePresentations.js" ""
Write-B64File "src\PresentationPage.js" ""
Write-B64File "src\AdminPage.js" ""
Write-B64File "src\presentations.css" ""
Write-B64File "supabase-schema.sql" ""
Write-B64File ".env.example" "IyBHZXQgdGhlc2UgZnJvbSB5b3VyIFN1cGFiYXNlIHByb2plY3Q6IFNldHRpbmdzID4gQVBJClJFQUNUX0FQUF9TVVBBQkFTRV9VUkw9aHR0cHM6Ly95b3VyLXByb2plY3QtaWQuc3VwYWJhc2UuY28KUkVBQ1RfQVBQX1NVUEFCQVNFX0FOT05fS0VZPXlvdXItYW5vbi1rZXktaGVyZQo="

Write-Host "`n=== Step 3: Create .env ===" -ForegroundColor Cyan
if (!(Test-Path ".env")) {
    Copy-Item ".env.example" ".env"
    Write-Host "  Created .env from .env.example - EDIT THIS with your Supabase credentials!" -ForegroundColor Yellow
} else {
    Write-Host "  .env already exists, skipping" -ForegroundColor Yellow
}

Write-Host "`n=== Step 4: Patch App.jsx ===" -ForegroundColor Cyan
$appPath = "src\App.jsx"
$app = [System.IO.File]::ReadAllText("$PWD\$appPath")

# Check if already patched
if ($app.Contains("AdminPage")) {
    Write-Host "  App.jsx already patched, skipping" -ForegroundColor Yellow
} else {
    # Add imports
    $app = $app.Replace(
        'import blogsContent from "./content/blogs.json";',
        "import blogsContent from `"./content/blogs.json`";`nimport PresentationPage from `"./PresentationPage`";`nimport AdminPage from `"./AdminPage`";`nimport `"./presentations.css`";"
    )

    # Add routes
    $oldRoute = '  let page;
  if (path.startsWith("/blog/")) {
    const slug = path.replace("/blog/", "");
    page = <BlogPostPage slug={slug} />;
  } else {'
    $newRoute = '  let page;
  // Customer presentations & admin
  if (path === "/admin") {
    page = <AdminPage />;
  } else if (path.startsWith("/p/")) {
    const slug = path.replace("/p/", "");
    page = <PresentationPage slug={slug} />;
  } else if (path.startsWith("/blog/")) {
    const slug = path.replace("/blog/", "");
    page = <BlogPostPage slug={slug} />;
  } else {'
    $app = $app.Replace($oldRoute, $newRoute)

    # Hide navbar/footer on presentation routes
    $oldReturn = '  return (
    <>
      <Navbar onCalcOpen={() => { setCalcOpen(true); trackEvent(''calculator_opened'', { source: ''navbar'' }); }} />
      {page}
      <Footer />
      <CalculatorLightbox isOpen={calcOpen} onClose={() => { setCalcOpen(false); if (path === ''/calculator'') window.location.hash = ''/''; }} />'
    $newReturn = '  const isPresentationRoute = path === "/admin" || path.startsWith("/p/");

  return (
    <>
      {!isPresentationRoute && <Navbar onCalcOpen={() => { setCalcOpen(true); trackEvent(''calculator_opened'', { source: ''navbar'' }); }} />}
      {page}
      {!isPresentationRoute && <Footer />}
      {!isPresentationRoute && <CalculatorLightbox isOpen={calcOpen} onClose={() => { setCalcOpen(false); if (path === ''/calculator'') window.location.hash = ''/''; }} />}'

    if ($app.Contains('<Navbar onCalcOpen')) {
        # Simpler approach: just do targeted replacements
        $app = $app.Replace(
            '      <Navbar onCalcOpen={() => { setCalcOpen(true);',
            '      {!isPresentationRoute && <Navbar onCalcOpen={() => { setCalcOpen(true);'
        )
        # Fix the closing of Navbar line
        $app = $app.Replace(
            "}} />`n      {page}`n      <Footer />`n      <CalculatorLightbox",
            "}} />}`n      {page}`n      {!isPresentationRoute && <Footer />}`n      {!isPresentationRoute && <CalculatorLightbox"
        )
        # Add isPresentationRoute const before return
        $app = $app.Replace(
            '  return (',
            "  const isPresentationRoute = path === `"/admin`" || path.startsWith(`"/p/`");`n`n  return ("
        )
    }

    [System.IO.File]::WriteAllText("$PWD\$appPath", $app, [System.Text.UTF8Encoding]::new($false))
    Write-Host "  Patched App.jsx with presentation routes" -ForegroundColor Green
}

Write-Host "`n============================================" -ForegroundColor Green
Write-Host " SETUP COMPLETE!" -ForegroundColor Green
